// Parser baseado na estrutura real do widget api-futebol.com.br
const html = $input.first().json.data || $input.first().json.body || String($input.first().json) || '';

// Mapeamento: abreviações do widget → códigos do nosso sistema
const WIDGET_MAP = {
  'MEX':'MEX','AFS':'RSA','COR':'KOR','TCH':'CZE','CAN':'CAN','BOS':'BIH',
  'CAT':'QAT','SUI':'SUI','BRA':'BRA','MAR':'MAR','HAI':'HAI','ESC':'SCO',
  'EUA':'USA','PAR':'PAR','AUS':'AUS','TUR':'TUR','ALE':'GER','CUR':'CUW',
  'CDM':'CIV','EQU':'ECU','HOL':'NED','JAP':'JPN','SUE':'SWE','TUN':'TUN',
  'BEL':'BEL','EGI':'EGY','IRA':'IRN','NZL':'NZL','ESP':'ESP','CAB':'CPV',
  'ARA':'KSA','URU':'URU','FRA':'FRA','SEN':'SEN','IRQ':'IRQ','NOR':'NOR',
  'ARG':'ARG','AGL':'ALG','AUT':'AUT','JOR':'JOR','POR':'POR','RDC':'COD',
  'UZB':'UZB','COL':'COL','ING':'ENG','CRO':'CRO','GAN':'GHA','PAN':'PAN',
  'RSA':'RSA','KOR':'KOR','CZE':'CZE','BIH':'BIH','QAT':'QAT','SCO':'SCO',
  'USA':'USA','GER':'GER','CUW':'CUW','CIV':'CIV','ECU':'ECU','NED':'NED',
  'JPN':'JPN','SWE':'SWE','EGY':'EGY','IRN':'IRN','CPV':'CPV','KSA':'KSA',
  'ALG':'ALG','COD':'COD','ENG':'ENG','GHA':'GHA'
};

const MATCHES = [
  {id:1,home:'MEX',away:'RSA'},{id:2,home:'KOR',away:'CZE'},{id:3,home:'CAN',away:'BIH'},
  {id:4,home:'USA',away:'PAR'},{id:5,home:'QAT',away:'SUI'},{id:6,home:'BRA',away:'MAR'},
  {id:7,home:'HAI',away:'SCO'},{id:8,home:'AUS',away:'TUR'},{id:9,home:'GER',away:'CUW'},
  {id:10,home:'CIV',away:'ECU'},{id:11,home:'NED',away:'JPN'},{id:12,home:'SWE',away:'TUN'},
  {id:13,home:'ESP',away:'CPV'},{id:14,home:'BEL',away:'EGY'},{id:15,home:'KSA',away:'URU'},
  {id:16,home:'IRN',away:'NZL'},{id:17,home:'FRA',away:'SEN'},{id:18,home:'IRQ',away:'NOR'},
  {id:19,home:'ARG',away:'ALG'},{id:20,home:'AUT',away:'JOR'},{id:21,home:'POR',away:'COD'},
  {id:22,home:'ENG',away:'CRO'},{id:23,home:'GHA',away:'PAN'},{id:24,home:'UZB',away:'COL'},
  {id:25,home:'CZE',away:'RSA'},{id:26,home:'SUI',away:'BIH'},{id:27,home:'CAN',away:'QAT'},
  {id:28,home:'MEX',away:'KOR'},{id:29,home:'USA',away:'AUS'},{id:30,home:'SCO',away:'MAR'},
  {id:31,home:'BRA',away:'HAI'},{id:32,home:'TUR',away:'PAR'},{id:33,home:'NED',away:'SWE'},
  {id:34,home:'GER',away:'CIV'},{id:35,home:'ECU',away:'CUW'},{id:36,home:'TUN',away:'JPN'},
  {id:37,home:'ESP',away:'KSA'},{id:38,home:'BEL',away:'IRN'},{id:39,home:'URU',away:'CPV'},
  {id:40,home:'NZL',away:'EGY'},{id:41,home:'ARG',away:'AUT'},{id:42,home:'FRA',away:'IRQ'},
  {id:43,home:'NOR',away:'SEN'},{id:44,home:'JOR',away:'ALG'},{id:45,home:'POR',away:'UZB'},
  {id:46,home:'ENG',away:'GHA'},{id:47,home:'PAN',away:'CRO'},{id:48,home:'COL',away:'COD'},
  {id:49,home:'MEX',away:'CZE'},{id:50,home:'RSA',away:'KOR'},{id:51,home:'SUI',away:'CAN'},
  {id:52,home:'BIH',away:'QAT'},{id:53,home:'SCO',away:'BRA'},{id:54,home:'MAR',away:'HAI'},
  {id:55,home:'TUR',away:'USA'},{id:56,home:'PAR',away:'AUS'},{id:57,home:'ECU',away:'GER'},
  {id:58,home:'CUW',away:'CIV'},{id:59,home:'JPN',away:'SWE'},{id:60,home:'TUN',away:'NED'},
  {id:61,home:'NOR',away:'FRA'},{id:62,home:'SEN',away:'IRQ'},{id:63,home:'CPV',away:'KSA'},
  {id:64,home:'URU',away:'ESP'},{id:65,home:'EGY',away:'IRN'},{id:66,home:'NZL',away:'BEL'},
  {id:67,home:'PAN',away:'ENG'},{id:68,home:'CRO',away:'GHA'},{id:69,home:'COL',away:'POR'},
  {id:70,home:'COD',away:'UZB'},{id:71,home:'JOR',away:'ARG'},{id:72,home:'ALG',away:'AUT'}
];

const toUpdate = [];

// Cada jogo está num bloco com class "grid grid-cols-3 mb-2 gap-x-7"
// Estrutura: <span>TIME1</span> ... <div class="text-xl text-center">GOL1</div> ... <div class="text-xl text-center">GOL2</div> ... <span>TIME2</span>
const blockRegex = /<div class="grid grid-cols-3 mb-2 gap-x-7">[\s\S]*?<\/div>\s*<\/div>\s*<\/div>/g;
const blocks = html.match(blockRegex) || [];

for (const block of blocks) {
  // Extrai abreviações de times (apenas letras maiúsculas 2-4 chars dentro de <span>)
  const spanMatches = [...block.matchAll(/<span[^>]*>([A-Z]{2,4})<\/span>/g)];
  // Extrai placares dos divs com classe text-xl text-center
  const scoreMatches = [...block.matchAll(/<div class="text-xl text-center">(\d*)<\/div>/g)];

  if (spanMatches.length < 2 || scoreMatches.length < 2) continue;

  const widgetHome = spanMatches[0][1].trim();
  const widgetAway = spanMatches[spanMatches.length - 1][1].trim();
  const scoreHome = scoreMatches[0][1].trim();
  const scoreAway = scoreMatches[1][1].trim();

  // Ignora jogos sem placar
  if (scoreHome === '' || scoreAway === '') continue;

  const homeCode = WIDGET_MAP[widgetHome];
  const awayCode = WIDGET_MAP[widgetAway];
  if (!homeCode || !awayCode) {
    console.log('Abreviação não mapeada:', widgetHome, widgetAway);
    continue;
  }

  const localMatch = MATCHES.find(m => m.home === homeCode && m.away === awayCode);
  if (!localMatch) {
    console.log('Jogo não encontrado:', homeCode, 'x', awayCode);
    continue;
  }

  if (!toUpdate.find(u => u.match_id === localMatch.id)) {
    toUpdate.push({ match_id: localMatch.id, home_score: parseInt(scoreHome), away_score: parseInt(scoreAway) });
  }
}

console.log('Blocos de jogo encontrados:', blocks.length);
console.log('Jogos com placar para atualizar:', JSON.stringify(toUpdate));

if (toUpdate.length === 0) {
  return [{ json: { debug: true, blocks_found: blocks.length, found: 0 } }];
}

return toUpdate.map(item => ({ json: item }));
